  ('social-worker-moex-05410', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為避免身心障礙者受到歧視偏見的暴力，在保護服務方面，須緊急保護安置或其他必要的處置，請問其 中須緊急保護安置者不得超過幾個小時？', '["24小時", "48小時", "72小時", "96小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05411', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '為維護身心障礙者的就業權利，身心障礙者權益保障法規定各級政府機關員工總人數在34人以上者，進 用具有就業能力之身心障礙者人數，不得低於員工總人數的比例為何？', '["1%", "2%", "3%", "5%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05412', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在老人保護的實證研究中發現，老人受虐經常與照顧問題有關，下列何者不是老人受虐導因於照顧者的 危險因子（risk factors）之一？', '["照顧者有高度照顧負荷", "照顧者酒精／藥物濫用問題", "照顧者有性別平等偏差問題", "照顧者自覺健康不佳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05413', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '臺灣在1998年6月通過家庭暴力防治法，使家庭暴力防治工作有了法源依據。有關臺灣受暴婦女的社會 工作實施方法的內容，下列敘述何者錯誤？', '["我國家庭暴力防治的特色是以網絡概念提供家庭暴力受害人保護服務，確立以各縣市家庭暴力防治中 心為主管單位，統籌警政、司法、教育、戶政與衛生醫療相關單位網絡，提供整合性服務", "工作重點則是以危險評估的工作模式為主，透過危險評估指標與專業人員判斷，與被害人討論危險情境 的認知和恐懼，提升被害人對於自身處境的危險意識，專業人員蒐集資訊，據以擬定準確的安全計畫", "評估工具一開始是使用中文版危險評估量表（Dangerous Assessment, DA），近年來則研發完成臺灣親密 關係暴力危險評估表（Taiwan Intimate Partner Violence Danger Assessment, TIPVDA），現已全面實施中", "發展出垂直整合的服務方案，接受通報後，由一名社工員啟動個案的相關服務，服務過程中明確區分 一線服務（危險處遇）和二線服務（後續追蹤服務），增加個案服務資源網絡與工作程序。目前個案 服務，以婚姻暴力被害人保護扶助輔導服務及目睹兒童少年的關懷服務為主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05414', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關基變觀點社會工作主要的理論觀點與概念的敘述，下列何者錯誤？', '["反對自由化的改革主義", "福利國家的設置基本上是反對資本主義社會的", "不信任專業主義", "提醒個人與社會間關係的假性二分法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05415', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '「工具性日常生活活動功能」量表（Instrumental Activities of Daily Living, IADLs）是用以評估老人獨立 自主生活能力的評估工具，下列那一種功能不是評估項目之一？', '["食物烹調", "穿脫衣褲", "使用電話", "上街購物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05416', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學校社會工作是在學校情境中，透過直接服務、系統性服務與倡導的方式，來支持與提升學生的學習和 福祉。有關學校社會工作的工作任務，下列何者錯誤？', '["兒少虐待預防與通報", "心理治療與諮商", "經濟弱勢資源連結", "中輟學生輔導與協助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05417', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '危機介入取向是以心理動力的自我心理學為基礎，針對足以導致個人正常功能產生混亂的事件所採取的 阻止行動，以解決危機情境。對於危機介入取向的基本假設，下列何者錯誤？', '["個人對危機情境之反應是反應出個人對目前壓力之認知經驗，而非個人病態", "當個人無力處理內在壓力或外在事件，而轉成危機事件時，將引發危機", "危機提供個人成長與發展機會，但結果是各不相同", "危機是暫時性的，而且沒有特定發展階段，持續時間也會因人而異"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05418', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會個案工作實務運作中，保密是一項重要的倫理原則。所謂的保密是社會個案工作者在服務過程中知 悉案主（家）的相關事情，不得透露給第三者知道，這樣的做法可使案主（家）放心透露相關資訊，以 利後續服務的進行。但是，在一些特殊的情形下，基於例外的情況下而採取不保密，下列何者錯誤？', '["基於保護案主（家）及第三者合法權益", "社會工作者考量專業自主性時", "提報特殊個案研討會討論時", "基於警告或通報責任時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05419', 'social-worker', 'social-worker-moex-106-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '會談是社會工作專業服務的一種具體程序，透過工作者與案主之間面對面的溝通，表現其專業服務活動。 有關會談的原則，下列何者錯誤？', '["同理與尊重案主經驗", "教育案主正確價值觀", "抱持開放與坦誠的態度", "慎用口語與非口語訊息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "525f8f9ddd82", "answer_pdf_sha1": "2451032c1fbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
